const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const isLongStanding = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
  isLongStanding(customer) ? -policyBase * LOYALTY_DISCOUNT_RATE : 0;

const firstInsuranceSurcharge = (policyBase: number): number =>
  policyBase * FIRST_INSURANCE_RATE;

const policyModifiers = (policyBase: number, customer: Customer): number =>
  firstInsuranceSurcharge(policyBase) + loyaltyDiscount(policyBase, customer);
